    private TreeNode deserializeHelper(String[] nodes) {
        int[] index = new int[]{0};
        return buildTree(nodes, Integer.MIN_VALUE, Integer.MAX_VALUE, index);
    }

    private TreeNode buildTree(String[] nodes, int minVal, int maxVal, int[] index) {
        if (index[0] >= nodes.length) {
            return null;
        }
        String val = nodes[index[0]];
        if (val.equals("#")) {
            index[0]++;
            return null;
        }
        int nodeVal = Integer.parseInt(val);
        if (nodeVal < minVal || nodeVal > maxVal) {
            return null;
        }
        TreeNode node = new TreeNode(nodeVal);
        index[0]++;
        node.left = buildTree(nodes, minVal, nodeVal, index);
        node.right = buildTree(nodes, nodeVal, maxVal, index);
        return node;
    }
